SELECT IFNULL(SUM(feedback_quantity), 0)     AS feedbackQuantity,
       IFNULL(SUM(qualified_quantity), 0)    AS qualifiedQuantity,
       IFNULL(SUM(unqualified_quantity), 0)  AS unqualifiedQuantity
FROM mes_pro_feedback
WHERE deleted = 0
  AND status = ${@cn.iocoder.yudao.module.mes.enums.pro.MesProFeedbackStatusEnum@FINISHED.status}
  AND feedback_time >= #{beginTime}

      AND feedback_time < #{endTime}

SELECT DATE_FORMAT(feedback_time, '%Y-%m-%d') AS date, IFNULL(SUM(feedback_quantity), 0) AS quantity, IFNULL(SUM(qualified_quantity), 0) AS qualifiedQuantity, IFNULL(SUM(unqualified_quantity), 0) AS unqualifiedQuantity FROM mes_pro_feedback WHERE deleted = 0 AND status = ${@cn.iocoder.yudao.module.mes.enums.pro.MesProFeedbackStatusEnum@FINISHED.status} AND feedback_time >= #{beginTime}
AND feedback_time < #{endTime}
GROUP BY DATE_FORMAT(feedback_time, '%Y-%m-%d') ORDER BY date
